sql:
SELECT COUNT(*) AS change_count
FROM borough_history
WHERE strftime('%Y', change_date) = '2020';

SELECT borough_id, MAX(change_date) AS last_change_date
FROM borough_history
GROUP BY borough_id;

SELECT layer_name, created_at 
FROM map_layers 
ORDER BY created_at DESC;

SELECT development_status, COUNT(*) as num_neighborhoods
FROM urban_planning
GROUP BY development_status;

external_knowledge:
- High-density neighborhoods are those with a population density greater than 1000 people per square kilometer; 
- Urban land use being 'defined' implies the neighborhood has specific land use designations, which could include residential, commercial, or mixed-use areas; 
- Public transit being 'available' suggests the presence of buses, trains, or other forms of shared transportation within the neighborhood.

sql:
SELECT layer_type, COUNT(layer_name) AS count_of_layers
FROM map_layers
GROUP BY layer_type;

SELECT public_transit, bike_lanes, road_network
FROM transportation
WHERE transportation_id = 0;

SELECT borough_id, change_type, description
FROM borough_history
WHERE change_type != 'name change';

external_knowledge:
- Population density refers to the number of people per unit area; 
- Boroughs and neighborhoods are administrative divisions used in various countries for governance and organization; 
- Boundary changes could include updates to neighborhood limits, name changes, or other modifications to the geographical area.

sql:
SELECT change_date 
FROM neighborhood_history 
WHERE change_type = 'boundary update';

SELECT COUNT(DISTINCT postcode) AS unique_postcodes
FROM postcodes
WHERE borough_id = 0;
